content_blocks.syntax:
graph TD
    A["High Addresses / OS Kernel Space"] --- B["Stack: Grows Downward"]
    B --- C["Empty Memory / Guard Pages"]
    C --- D["Heap: Grows Upward"]
    D --- E[".bss: Uninitialized Globals"]
    E --- F[".data: Initialized Globals"]
    F --- G[".text: Executable Code / Read-Only"]
    G --- H["0x00000000 - Null Pointer Trap"]
    classDef mem fill:#18181b,stroke:#3b82f6,stroke-width:2px,color:#f4f4f5;
    classDef danger fill:#450a0a,stroke:#ef4444,stroke-width:2px,color:#ef4444;
    class A,H danger;
    class B,C,D,E,F,G mem;

