#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;

// .data segment: Initialized globally
int global_config = 42;

// .bss segment: Uninitialized (automatically zeroed by OS)
int global_buffer[1024];

int main() {
    // Stack segment: Local to main's frame
    int local_var = 10;

    // Heap segment: Dynamically requested at runtime
    int *dynamic_ptr = (int *)malloc(sizeof(int));
    *dynamic_ptr = 99;

    printf(".data Address: %p\n", (void*)&global_config);
    printf(".bss  Address: %p\n", (void*)&global_buffer);
    printf("Heap  Address: %p\n", (void*)dynamic_ptr);
    printf("Stack Address: %p\n", (void*)&local_var);

    free(dynamic_ptr);
    return 0;
}

#include &lt;stdio.h&gt;

char* get_status_message(int code) {
    char msg[64];
    if (code == 200) {
        snprintf(msg, sizeof(msg), "OK - All systems go.");
    } else {
        snprintf(msg, sizeof(msg), "ERROR - System fault.");
    }
    return msg;
}

int main() {
    char* ptr = get_status_message(200);
    printf("Status: %s\n", ptr);
    return 0;
}

#include &lt;stdio.h&gt;

// 1. Static Global: Internal Linkage (Hidden from Linker)
// Exists in .data. Other files CANNOT 'extern' this variable.
static int module_state = 1;

void process() {
    // 2. Static Local: Extended Lifetime
    // Exists in .data (NOT the Stack). It initializes to 0 ONCE at boot.
    // It retains its value across multiple calls to process().
    static int call_count = 0;

    call_count++;
    printf("Called %d times.\n", call_count);
}

// --- config.c ---
// Definition: Memory is physically allocated here.
int system_timeout = 300;

// --- main.c ---
#include &lt;stdio.h&gt;

// Declaration: Promises the compiler that this variable is defined 
// in another translation unit. Does NOT allocate memory.
extern int system_timeout;

int main() {
    printf("Timeout: %d\n", system_timeout);
    return 0;
}

// --- shared_vars.h ---
#ifndef SHARED_VARS_H
#define SHARED_VARS_H

// Global configuration state
int max_retries = 5;

#endif

// --- file1.c ---
#include "shared_vars.h"
void init() { max_retries = 10; }

// --- file2.c ---
#include "shared_vars.h"
void execute() { /* logic */ }

#include &lt;stdio.h&gt;
#include &lt;threads.h&gt; // C11 Threading

// 1. A standard global. All threads mutate this single memory address.
int shared_global = 0;

// 2. A Thread-Local global. Every thread gets a private copy.
thread_local int private_counter = 0;

int thread_work(void *arg) {
    int id = *(int*)arg;

    // Both threads execute this code.
    shared_global++;
    private_counter++;

    printf("Thread %d: Shared=%d, Private=%d\n", id, shared_global, private_counter);
    return 0;
}

#include &lt;string.h&gt;
#include &lt;stdio.h&gt;
#include &lt;pthread.h&gt;

void* parse_log(void* arg) {
    char buffer[] = "ERROR,404,SYSTEM_FAULT";
    // strtok uses internal 'static' state to remember where it left off
    char *token = strtok(buffer, ",");
    while (token != NULL) {
        printf("Token: %s\n", token);
        token = strtok(NULL, ",");
    }
    return NULL;
}

int main() {
    pthread_t t1, t2;
    pthread_create(&t1, NULL, parse_log, NULL);
    pthread_create(&t2, NULL, parse_log, NULL);
    pthread_join(t1, NULL);
    pthread_join(t2, NULL);
    return 0;
}

; C Code: thread_local int tls_var;
; C Code: tls_var = 5;

; The CPU uses the 'fs' segment register. The exact offset 
; is resolved by the Linker depending on the TLS model.
mov     DWORD PTR fs:tls_var@tpoff, 5
